import{_ as e,o as i,c as t,a2 as s}from"./chunks/framework.B8zgMDLd.js";const m=JSON.parse('{"title":"Files And Media","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/files-and-media.md","filePath":"concepts/files-and-media.md"}'),n={name:"concepts/files-and-media.md"};function r(o,a,d,l,h,p){return i(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="files-and-media" tabindex="-1">Files And Media <a class="header-anchor" href="#files-and-media" aria-label="Permalink to &quot;Files And Media&quot;">​</a></h1><p>Tolaria starts with Markdown notes, but a vault can also contain images, PDFs, media files, whiteboards, and other local files.</p><h2 id="mermaid-diagrams" tabindex="-1">Mermaid Diagrams <a class="header-anchor" href="#mermaid-diagrams" aria-label="Permalink to &quot;Mermaid Diagrams&quot;">​</a></h2><p>Use Mermaid code blocks when a note needs a diagram that should stay plain text and versionable.</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```mermaid</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Idea --&gt; Draft --&gt; Review --&gt; Publish</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">```</span></span></code></pre></div><p>Tolaria renders Mermaid diagrams in the editor while keeping the source in Markdown.</p><h2 id="attachments" tabindex="-1">Attachments <a class="header-anchor" href="#attachments" aria-label="Permalink to &quot;Attachments&quot;">​</a></h2><p>Images pasted into the editor are saved into the vault as normal files. They remain portable and can be opened by other tools.</p><h2 id="previews" tabindex="-1">Previews <a class="header-anchor" href="#previews" aria-label="Permalink to &quot;Previews&quot;">​</a></h2><p>Tolaria can preview common image files, PDFs, and supported media files in the app. Files without an in-app preview can still be opened in the default system app.</p><p>Settings control whether PDFs, images, and unsupported files appear in All Notes. Folder browsing still shows files in their folders.</p><h2 id="whiteboards" tabindex="-1">Whiteboards <a class="header-anchor" href="#whiteboards" aria-label="Permalink to &quot;Whiteboards&quot;">​</a></h2><p>Whiteboards use tldraw in the editor, but their durable representation stays in Markdown. That keeps them inside the vault and versioned by Git with the rest of your notes.</p><h2 id="git-boundary" tabindex="-1">Git Boundary <a class="header-anchor" href="#git-boundary" aria-label="Permalink to &quot;Git Boundary&quot;">​</a></h2><p>If generated or local-only files are ignored by Git, Tolaria can hide them from notes, search, quick open, and folders. Use this when build artifacts or private local files should not behave like vault content.</p>',15)])])}const u=e(n,[["render",r]]);export{m as __pageData,u as default};
